#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int n; long long x, y; scanf("%d %lld %lld", &n, &x, &y);
        long long sum=0, disc=0, a;
        for(int i=0;i<n;i++){
            scanf("%lld", &a);
            sum+=a;
            long long after = a - y;
            if(after>0) disc+=after;
        }
        if(x + disc < sum) printf("COUPON\n");
        else printf("NO COUPON\n");
    }
    return 0;
}

